import React, { useRef, useState } from "react";
// Import Swiper React components
import { Swiper, SwiperSlide } from "swiper/react";

// Import Swiper styles
import "swiper/css";
import "swiper/css/effect-coverflow";
import "swiper/css/pagination";

import "./sty.css";

// import required modules
import {
  Autoplay,
  EffectCoverflow,
  Navigation,
  Pagination,
} from "swiper/modules";

// Import your images or use placeholders
import image1 from "./car-1.png";
import image2 from "./car-2.png";
import image3 from "./car-3.png";

const MySwiper = () => {
  return (
    <>
      <Swiper
        effect={"coverflow"}
        grabCursor={true}
        centeredSlides={true}
        slidesPerView={"auto"}
        coverflowEffect={{
          rotate: 180,
          stretch: 0,
          depth: 500,
          modifier: 2,
          slideShadows: false,
        }}
        navigation={true}
        autoplay={{
          delay: 1500,
        }}
        rewind={true}
        spaceBetween={30}
        pagination={{
          clickable: true,
          type: "bullets",
        }}
        modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
        className="mySwiper"
      >
        <SwiperSlide>
          <img src={image1} />
        </SwiperSlide>
        <SwiperSlide>
          <img src={image2} />
        </SwiperSlide>
        <SwiperSlide>
          <img src={image3} />
        </SwiperSlide>
      </Swiper>
    </>
  );
};

export default MySwiper;
